mapper.select:
SELECT * FROM shop

    status = 0

        AND (name LIKE CONCAT('%',#{q.keyword},'%') OR description LIKE CONCAT('%',#{q.keyword},'%'))


        AND category = #{q.category}


        AND score >= #{q.minScore}


        AND student_discount = #{q.studentDiscount}



    ORDER BY score DESC
    ORDER BY like_count DESC, review_count DESC

        ORDER BY ST_Distance_Sphere(POINT(longitude, latitude), POINT(#{q.longitude}, #{q.latitude})) ASC

    ORDER BY created_at DESC

LIMIT #{offset}, #{q.size}

SELECT COUNT(*) FROM shop

    status = 0

        AND (name LIKE CONCAT('%',#{q.keyword},'%') OR description LIKE CONCAT('%',#{q.keyword},'%'))


        AND category = #{q.category}


        AND score >= #{q.minScore}


        AND student_discount = #{q.studentDiscount}
